    x &= x - 1;
    count++;
  }
  return count;
}

function computeDepth(x: number): number {
  if (x === 1) return 0;
  let depth = 0;
  let current = x;
  while (current !== 1) {
    current = popcount(current);
    depth++;
    if (current === 1) break;
  }
  return depth;
}

function solve(nums: number[], queries: number[][]): number[] {
  const depths: number[] = nums.map(x => computeDepth(x));
  const ft: FenwickTree[] = Array(6).fill(null).map(() => new FenwickTree(nums.length));

  for (let i = 0; i < nums.length; i++) {
    const d = depths[i];
    if (d <= 5) {
      ft[d].update(i + 1, 1);
    }
  }

  const answer: number[] = [];

  for (const q of queries) {
    if (q[0] === 1) {
      const l = q[1];
      const r = q[2];
      const k = q[3];
      if (k > 5) {
        answer.push(0);
        continue;
      }
      const sum = ft[k].query(r + 1) - ft[k].query(l);
      answer.push(sum);
    } else {
      const idx = q[1];
      const val = q[2];
      const oldVal = nums[idx];
      const oldDepth = depths[idx];
      if (oldDepth <= 5) {
        ft[oldDepth].update(idx + 1, -1);
      }
      const newDepth = computeDepth(val);
      nums[idx] = val;
      depths[idx] = newDepth;
      if (newDepth <= 5) {
        ft[newDepth].update(idx + 1, 1);
      }
    }
  }

  return answer;
}
